import { useState, useEffect, useRef } from 'react';
import { usePrivy, useWallets } from './hooks/privy';
import { LandingPage } from './components/LandingPage';
import { Dashboard } from './components/Dashboard';
import { PlansPage } from './components/PlansPage';
import { YieldDashboard } from './components/YieldDashboard';
import { SharedVault } from './components/SharedVault';
import { SwapPage } from './components/SwapPage';
import { Sidebar } from './components/Sidebar';
import { CreatePlanModal } from './components/CreatePlanModal';
import { DepositModal } from './components/DepositModal';
import { SendModal } from './components/SendModal';
import { ReceiveModal } from './components/ReceiveModal';
import { WalletManager } from './components/WalletManager';
import { TourGuide } from './components/TourGuide';
import { UserProfile } from './components/UserProfile';
import { NotificationCenter, type Notification } from './components/NotificationCenter';
import { Icon } from './components/Icon';
import { CurrencyProvider } from './context/CurrencyContext';
import { ReferralsPage } from './components/ReferralsPage';
import { LeaderboardPage } from './components/LeaderboardPage';
import type { SavingsPlan } from './types';

type Tab = 'dashboard' | 'plans' | 'swap' | 'yield' | 'referrals' | 'leaderboard';

function App() {
  const { authenticated, ready, user, logout } = usePrivy();
  const { wallets } = useWallets();

  const [activeTab, setActiveTab] = useState<Tab>('dashboard');
  const [plans, setPlans] = useState<SavingsPlan[]>([]);
  const [selectedPlan, setSelectedPlan] = useState<SavingsPlan | null>(null);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showDepositModal, setShowDepositModal] = useState<SavingsPlan | null>(null);
  const [showSendModal, setShowSendModal] = useState(false);
  const [showReceiveModal, setShowReceiveModal] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [showDropdown, setShowDropdown] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [profileUsername, setProfileUsername] = useState<string | null>(null);
  const [lastVaultState, setLastVaultState] = useState<Map<string, number>>(new Map());
  const dropdownRef = useRef<HTMLDivElement>(null);
  const pollingIntervalRef = useRef<NodeJS.Timeout | null>(null);

  const privy_id = user?.id || '';
  const wallet = wallets.find(w => (w as any).walletClientType === 'privy' || w.address.startsWith('0x'));
  const address = wallet?.address ?? '';

  // Notification Management
  const addNotification = (type: 'success' | 'error' | 'info' | 'update', message: string, action?: { label: string; onClick: () => void }) => {
    const notif: Notification = {
      id: `${Date.now()}_${Math.random()}`,
      type,
      message,
      timestamp: new Date(),
      read: false,
      action,
    };
    setNotifications(prev => [notif, ...prev]);

    // Persist to localStorage
    const stored = localStorage.getItem('equilibria_notifications');
    const history = stored ? JSON.parse(stored) : [];
    localStorage.setItem('equilibria_notifications', JSON.stringify([
      { ...notif, timestamp: notif.timestamp.toISOString() },
      ...history,
    ].slice(0, 50))); // Keep last 50 notifications
  };

  const markNotificationAsRead = (id: string) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  };

  const clearNotifications = () => {
    setNotifications([]);
    localStorage.removeItem('equilibria_notifications');
  };

  // Load notification history on mount
  useEffect(() => {
    const stored = localStorage.getItem('equilibria_notifications');
    if (stored) {
      try {
        const history = JSON.parse(stored).map((n: any) => ({
          ...n,
          timestamp: new Date(n.timestamp),
        }));
        setNotifications(history.slice(0, 20)); // Load last 20
      } catch (e) {
        console.error('Failed to load notifications:', e);
      }
    }
  }, []);

  // Register user on first login
  useEffect(() => {
    if (authenticated && privy_id && address) {
      registerUser();
      syncVaultsFromBackend();
      // Start real-time polling loop
      startPolling();
    }
    return () => {
      if (pollingIntervalRef.current) {
        clearInterval(pollingIntervalRef.current);
      }
    };
  }, [authenticated, privy_id, address]);

  const startPolling = () => {
    // Poll for vault updates every 10 seconds
    pollingIntervalRef.current = setInterval(() => {
      checkForVaultUpdates();
    }, 10000);
  };

  const checkForVaultUpdates = async () => {
    try {
      const response = await fetch(`/api/vaults/${address}`);
      if (!response.ok) return;

      const data = await response.json();
      const backendVaults = data.vaults || [];

      // Check for balance changes
      for (const vault of backendVaults) {
        const planId = vault.planId;
        const oldBalance = lastVaultState.get(planId) || 0;
        const newBalance = vault.currentAmount || 0;

        if (newBalance > oldBalance && oldBalance > 0) {
          const delta = newBalance - oldBalance;
          addNotification(
            'update',
            `Partner deposited $${delta.toFixed(2)} to "${vault.planName}"`,
            {
              label: 'View',
              onClick: () => {
                const plan = plans.find(p => p.id === planId);
                if (plan) setSelectedPlan(plan);
              },
            }
          );
        }

        setLastVaultState(prev => new Map(prev).set(planId, newBalance));
      }

      setPlans(prevPlans =>
        prevPlans.map(plan => {
          const vault = backendVaults.find((v: any) => v.planId === plan.id);
          if (vault) {
            return {
              ...plan,
              currentAmount: vault.currentAmount || plan.currentAmount,
              partnerContribution: vault.creatorAddress === address ? vault.partnerContribution || 0 : vault.creatorContribution || 0,
            };
          }
          return plan;
        })
      );
    } catch (err) {
      console.error('Failed to check vault updates:', err);
    }
  };

  const syncVaultsFromBackend = async () => {
    try {
      const response = await fetch(`/api/vaults/${address}`);
      if (!response.ok) return;

      const data = await response.json();
      const backendVaults = data.vaults || [];

      // Merge backend vaults with local plans
      const vaultMap = new Map(plans.map(p => [p.id, p]));

      for (const vault of backendVaults) {
        const planId = vault.planId;
        const vaultBalance = vault.currentAmount || 0;
        setLastVaultState(prev => new Map(prev).set(planId, vaultBalance));

        if (!vaultMap.has(planId)) {
          // Partner was added to a plan created by someone else
          const synced: SavingsPlan = {
            id: planId,
            name: vault.planName,
            category: 'other',
            type: 'joint',
            token: vault.token as any,
            targetAmount: vault.targetAmount,
            currentAmount: vaultBalance,
            myContribution: 0,
            partnerContribution: 0,
            yieldEarned: 0,
            apy: 4.2,
            createdAt: vault.createdAt,
            lockDurationDays: 30,
            withdrawalDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
            depositToDefi: true,
            policyAgreed: true,
            sharedOnX: false,
            partnerAddress: vault.creatorAddress === address ? vault.partnerAddress : vault.creatorAddress,
            partnerInviteCode: vault.inviteCode,
            isPartnerAccepted: vault.isPartnerAccepted,
          };
          vaultMap.set(planId, synced);

          // Show notification if this is a partner join
          if (vault.partnerAddress === address) {
            addNotification(
              'info',
              `You were added to "${vault.planName}" by partner!`,
              {
                label: 'Open',
                onClick: () => {
                  const plan = vaultMap.get(planId);
                  if (plan) setSelectedPlan(plan);
                },
              }
            );
          }
        }
      }

      setPlans(Array.from(vaultMap.values()));
    } catch (err) {
      console.error('Failed to sync vaults:', err);
    }
  };

  const registerUser = async () => {
    try {
      // Check if user already registered
      const existing = localStorage.getItem(`equilibria_user_${privy_id}`);
      if (existing) return;

      const username = `user_${privy_id.slice(0, 8)}`.toLowerCase();
      await fetch('/api/users', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          privy_id,
          address,
          username,
          displayName: username,
        }),
      });
      localStorage.setItem(`equilibria_user_${privy_id}`, 'true');
    } catch (err) {
      console.error('Failed to register user:', err);
    }
  };

  // Check URL for user profile
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const profile = params.get('profile');
    if (profile) {
      setProfileUsername(profile);
    }
  }, []);

  // Listen for URL changes
  useEffect(() => {
    const handlePopState = () => {
      const params = new URLSearchParams(window.location.search);
      const profile = params.get('profile');
      setProfileUsername(profile);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const closeUserProfile = () => {
    setProfileUsername(null);
    window.history.pushState({}, '', window.location.pathname);
  };

  // Close dropdown if clicked outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowDropdown(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  useEffect(() => {
    const saved = localStorage.getItem('equilibria_plans');
    if (saved) { try { setPlans(JSON.parse(saved)); } catch (e) { console.error(e); } }
    const savedTheme = localStorage.getItem('equilibria_theme');
    if (savedTheme === 'light' || savedTheme === 'dark') setTheme(savedTheme as 'light' | 'dark');
  }, []);

  useEffect(() => {
    localStorage.setItem('equilibria_plans', JSON.stringify(plans));
    localStorage.setItem('equilibria_theme', theme);
  }, [plans, theme]);

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const addPlan = async (newPlan: SavingsPlan) => {
    try {
      // Persist joint vaults to backend
      if (newPlan.type === 'joint' && newPlan.partnerAddress) {
        const response = await fetch('/api/vaults', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            planId: newPlan.id,
            creatorAddress: address,
            partnerAddress: newPlan.partnerAddress,
            inviteCode: newPlan.partnerInviteCode,
            planName: newPlan.name,
            token: newPlan.token,
            targetAmount: newPlan.targetAmount,
          }),
        });

        if (!response.ok) {
          const err = await response.json();
          addNotification('error', `Failed to create vault: ${err.error}`);
          return;
        }

        addNotification(
          'success',
          `Plan created! ${newPlan.partnerAddress.slice(0, 6)}...${newPlan.partnerAddress.slice(-4)} can now join.`,
          {
            label: 'View',
            onClick: () => setSelectedPlan(newPlan),
          }
        );
      }

      setPlans(prev => [...prev, newPlan]);
      setShowCreateModal(false);
      setActiveTab('plans');
    } catch (err) {
      console.error('Failed to add plan:', err);
      addNotification('error', 'Failed to create plan');
    }
  };

  const updatePlan = (updatedPlan: SavingsPlan) => {
    setPlans(prev => prev.map(p => p.id === updatedPlan.id ? updatedPlan : p));
    if (selectedPlan?.id === updatedPlan.id) setSelectedPlan(updatedPlan);
  };

  const handleDeposit = (plan: SavingsPlan, amount: number) => {
    const updatedPlan: SavingsPlan = {
      ...plan,
      currentAmount: plan.currentAmount + amount,
      myContribution: plan.myContribution + amount,
      depositToDefi: true,
      yieldEarned: plan.yieldEarned + (amount * 0.0001)
    };
    updatePlan(updatedPlan);
    setShowDepositModal(null);
  };

  if (!ready) {
    return (
      <div style={{ background: 'var(--bg-root)', height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <span className="spinner" style={{ width: 40, height: 40, borderTopColor: 'var(--accent-primary)' }} />
      </div>
    );
  }

  if (!authenticated) return <LandingPage />;

  return (
    <CurrencyProvider>
      <div className="app-layout">
        <TourGuide />

        <Sidebar
          activeTab={activeTab}
          setActiveTab={(t) => { setActiveTab(t); setSelectedPlan(null); setShowSettings(false); }}
        />

        <div className="main-container">
          <header className="top-header">
            <div style={{ flex: 1 }} />

            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
              <button 
                className="tour-guide-button" 
                onClick={() => window.dispatchEvent(new Event('startTour'))} 
                title="Take a Tour"
              >
                <Icon name="life_ring" size={18} />
              </button>
              <button className="btn-icon" onClick={toggleTheme} style={{ flexShrink: 0 }} title="Toggle Theme">
                <Icon name={theme === 'light' ? 'dark_mode' : 'light_mode'} size={20} />
              </button>
              <NotificationCenter
                notifications={notifications}
                onClear={clearNotifications}
                onMarkAsRead={markNotificationAsRead}
              />

              <div style={{ position: 'relative' }} ref={dropdownRef}>
                <div
                  className="btn-icon"
                  id="user-wallet-dropdown"
                  style={{ width: 'auto', padding: '0 0.75rem', gap: '0.5rem', cursor: 'pointer', background: showDropdown ? 'var(--bg-card-hover)' : 'var(--bg-card)' }}
                  onClick={() => setShowDropdown(!showDropdown)}
                >
                  <Icon name="account_circle" size={20} color="var(--accent-primary)" />
                  <span className="wallet-address-text" style={{ fontSize: '0.85rem', fontWeight: 700, color: 'var(--text-primary)' }}>
                    {address ? `${address.slice(0, 4)}...${address.slice(-4)}` : 'Guest'}
                  </span>
                  <Icon name={showDropdown ? 'expand_less' : 'expand_more'} size={18} />
                </div>

                {showDropdown && (
                  <div style={{
                    position: 'absolute', top: '110%', right: 0, width: '220px',
                    background: 'var(--bg-card)', border: '1px solid var(--border-subtle)',
                    borderRadius: '12px', boxShadow: '0 8px 32px rgba(0,0,0,0.12)',
                    overflow: 'hidden', zIndex: 200, display: 'flex', flexDirection: 'column'
                  }}>
                    <div style={{ padding: '1rem', borderBottom: '1px solid var(--border-subtle)' }}>
                      <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginBottom: '0.2rem' }}>Connected Wallet</div>
                      <div style={{ fontFamily: 'monospace', fontSize: '0.8rem', fontWeight: 600, color: 'var(--text-primary)' }}>
                        {address ? `${address.slice(0, 10)}...${address.slice(-6)}` : 'No wallet'}
                      </div>
                    </div>

                    <button
                      onClick={() => { setShowSettings(true); setShowDropdown(false); setSelectedPlan(null); }}
                      style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', padding: '0.8rem 1rem', background: 'transparent', border: 'none', color: 'var(--text-primary)', cursor: 'pointer', fontSize: '0.9rem', fontWeight: 600, textAlign: 'left' }}
                      onMouseEnter={e => (e.currentTarget.style.background = 'var(--bg-input)')}
                      onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                    >
                      <Icon name="settings" size={18} /> Settings & Profile
                    </button>

                    <button
                      onClick={logout}
                      style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', padding: '0.8rem 1rem', background: 'transparent', border: 'none', color: 'var(--danger)', cursor: 'pointer', fontSize: '0.9rem', fontWeight: 600, borderTop: '1px solid var(--border-subtle)', textAlign: 'left' }}
                      onMouseEnter={e => (e.currentTarget.style.background = 'var(--bg-input)')}
                      onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                    >
                      <Icon name="power_settings_new" size={18} /> Logout
                    </button>
                  </div>
                )}
              </div>
            </div>
          </header>

          {/* Recent Toast Notification */}
          {notifications.length > 0 && !notifications[0].read && (
            <div style={{
              padding: '0.875rem 1.5rem',
              marginBottom: '1rem',
              borderRadius: 10,
              fontSize: '0.9rem',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              gap: '0.75rem',
              animation: 'slideDown 0.3s ease-out',
              background: notifications[0].type === 'success' 
                ? 'rgba(16, 217, 160, 0.1)' 
                : notifications[0].type === 'error'
                ? 'rgba(239, 68, 68, 0.1)'
                : notifications[0].type === 'update'
                ? 'rgba(245, 158, 11, 0.1)'
                : 'rgba(59, 130, 246, 0.1)',
              border: `1px solid ${
                notifications[0].type === 'success'
                ? 'rgba(16, 217, 160, 0.3)'
                : notifications[0].type === 'error'
                ? 'rgba(239, 68, 68, 0.3)'
                : notifications[0].type === 'update'
                ? 'rgba(245, 158, 11, 0.3)'
                : 'rgba(59, 130, 246, 0.3)'
              }`,
              color: notifications[0].type === 'success'
                ? '#10d9a0'
                : notifications[0].type === 'error'
                ? '#ef4444'
                : notifications[0].type === 'update'
                ? '#f59e0b'
                : '#3b82f6',
            }}>
              <Icon 
                name={notifications[0].type === 'success' ? 'check_circle' : notifications[0].type === 'error' ? 'error' : notifications[0].type === 'update' ? 'info' : 'notification_important'} 
                size={18}
              />
              <span style={{ flex: 1 }}>{notifications[0].message}</span>
              {notifications[0].action && (
                <button
                  className="btn-text"
                  onClick={notifications[0].action.onClick}
                  style={{ padding: '0.25rem 0.75rem', fontSize: '0.8rem', color: 'inherit', opacity: 0.8 }}
                >
                  {notifications[0].action.label}
                </button>
              )}
            </div>
          )}

          <main className="scroll-content">
            {profileUsername ? (
              <UserProfile
                username={profileUsername}
                currentUserPrivy_id={privy_id}
                onClose={closeUserProfile}
              />
            ) : showSettings ? (
              <WalletManager onClose={() => setShowSettings(false)} />
            ) : selectedPlan ? (
              <SharedVault
                plan={selectedPlan}
                wallet={wallet}
                onBack={() => setSelectedPlan(null)}
                onUpdatePlan={updatePlan}
              />
            ) : (
              <>
                {activeTab === 'dashboard' && (
                  <div id="dashboard-summary">
                    <Dashboard
                      plans={plans}
                      onCreatePlan={() => setShowCreateModal(true)}
                      onSelectPlan={setSelectedPlan}
                      onDeposit={setShowDepositModal}
                      onUpdatePlan={updatePlan}
                      onGoToStore={() => setActiveTab('yield')}
                      onSend={() => setShowSendModal(true)}
                      onReceive={() => setShowReceiveModal(true)}
                      onSwap={() => setActiveTab('swap')}
                    />
                  </div>
                )}
                {activeTab === 'plans' && (
                  <PlansPage
                    plans={plans}
                    onCreatePlan={() => setShowCreateModal(true)}
                    onSelectPlan={setSelectedPlan}
                    onDeposit={setShowDepositModal}
                    onUpdatePlan={updatePlan}
                  />
                )}
                {activeTab === 'swap' && (
                  <SwapPage plans={plans} wallet={wallet} />
                )}
                {activeTab === 'yield' && (
                  <YieldDashboard plans={plans} wallet={wallet} />
                )}
                {activeTab === 'referrals' && (
                  <ReferralsPage plans={plans} userAddress={address} username={user?.id || ''} />
                )}
                {activeTab === 'leaderboard' && (
                  <LeaderboardPage />
                )}
              </>
            )}
          </main>
        </div>
      </div>

      {showCreateModal && (
        <CreatePlanModal onClose={() => setShowCreateModal(false)} onCreated={addPlan} privy_id={privy_id} />
      )}
      {showDepositModal && (
        <DepositModal
          plan={showDepositModal}
          wallet={wallet}
          onClose={() => setShowDepositModal(null)}
          onDeposited={handleDeposit}
        />
      )}
      {showSendModal && (
        <SendModal
          onClose={() => setShowSendModal(false)}
          onSent={(amount, recipient) => {
            console.log(`Sent ${amount} to ${recipient}`);
          }}
        />
      )}
      {showReceiveModal && (
        <ReceiveModal
          onClose={() => setShowReceiveModal(false)}
          walletAddress={address}
        />
      )}
    </CurrencyProvider>
  );
}

export default App;

import { Icon } from './Icon';

export interface ActivityEvent {
  id: string;
  planId: string;
  type: 'deposit' | 'withdrawal_requested' | 'withdrawal_approved' | 'withdrawal_rejected' | 'withdrawal_executed' | 'partner_joined' | 'vault_created';
  actor: string;
  amount: number;
  metadata: Record<string, any>;
  createdAt: Date;
}

interface Props {
  events: ActivityEvent[];
  isLoading?: boolean;
}

export function ActivityFeed({ events, isLoading = false }: Props) {
  const formatTime = (date: Date): string => {
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const mins = Math.floor(diff / 60000);
    const hours = Math.floor(diff / 3600000);
    const days = Math.floor(diff / 86400000);

    if (mins < 1) return 'just now';
    if (mins < 60) return `${mins}m ago`;
    if (hours < 24) return `${hours}h ago`;
    if (days < 7) return `${days}d ago`;
    
    return date.toLocaleDateString();
  };

  const getEventConfig = (type: ActivityEvent['type']) => {
    const configs: Record<string, { icon: string; color: string; label: string }> = {
      vault_created: { icon: 'add_circle', color: '#3b82f6', label: 'Vault Created' },
      partner_joined: { icon: 'person_add', color: '#10d9a0', label: 'Partner Joined' },
      deposit: { icon: 'download', color: '#10d9a0', label: 'Deposited' },
      withdrawal_requested: { icon: 'payment', color: '#f59e0b', label: 'Withdrawal Requested' },
      withdrawal_approved: { icon: 'check_circle', color: '#10d9a0', label: 'Withdrawal Approved' },
      withdrawal_rejected: { icon: 'cancel', color: '#ef4444', label: 'Withdrawal Rejected' },
      withdrawal_executed: { icon: 'send', color: '#8b5cf6', label: 'Withdrawal Executed' },
    };
    return configs[type] || { icon: 'info', color: '#6b7280', label: 'Event' };
  };

  const formatActorAddress = (address: string): string => {
    if (!address) return 'Unknown';
    if (address.length > 10) return `${address.slice(0, 6)}...${address.slice(-4)}`;
    return address;
  };

  if (isLoading) {
    return (
      <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-muted)' }}>
        <Icon name="schedule" size={32} style={{ opacity: 0.5, marginBottom: '0.5rem' }} />
        <div>Loading activity...</div>
      </div>
    );
  }

  if (events.length === 0) {
    return (
      <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-muted)' }}>
        <Icon name="history" size={32} style={{ opacity: 0.5, marginBottom: '0.5rem' }} />
        <div>No activity yet</div>
      </div>
    );
  }

  return (
    <div style={{ position: 'relative' }}>
      {/* Timeline line */}
      <div
        style={{
          position: 'absolute',
          left: '16px',
          top: 0,
          bottom: 0,
          width: '2px',
          background: 'linear-gradient(to bottom, var(--border-subtle), transparent)',
        }}
      />

      {/* Events */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        {events.map((event) => {
          const config = getEventConfig(event.type);

          return (
            <div key={event.id} style={{ position: 'relative', paddingLeft: '4rem' }}>
              {/* Timeline dot */}
              <div
                style={{
                  position: 'absolute',
                  left: 0,
                  top: '0.5rem',
                  width: '34px',
                  height: '34px',
                  borderRadius: '50%',
                  background: config.color,
                  border: '3px solid var(--bg-card)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: 'white',
                  zIndex: 10,
                }}
              >
                <Icon name={config.icon} size={16} color="white" />
              </div>

              {/* Event card */}
              <div
                style={{
                  background: 'var(--bg-input)',
                  border: '1px solid var(--border-subtle)',
                  borderRadius: 12,
                  padding: '1rem',
                  transition: 'all 0.2s',
                }}
                onMouseEnter={e => {
                  (e.currentTarget as HTMLElement).style.borderColor = 'var(--border-active)';
                  (e.currentTarget as HTMLElement).style.background = 'var(--bg-card)';
                }}
                onMouseLeave={e => {
                  (e.currentTarget as HTMLElement).style.borderColor = 'var(--border-subtle)';
                  (e.currentTarget as HTMLElement).style.background = 'var(--bg-input)';
                }}
              >
                {/* Header */}
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <span style={{ fontSize: '0.95rem', fontWeight: 600, color: 'var(--text-primary)' }}>
                      {config.label}
                    </span>
                    {event.amount > 0 && (
                      <span style={{ fontSize: '0.9rem', fontWeight: 700, color: config.color }}>
                        ${event.amount.toFixed(2)}
                      </span>
                    )}
                  </div>
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                    {formatTime(typeof event.createdAt === 'string' ? new Date(event.createdAt) : event.createdAt)}
                  </span>
                </div>

                {/* Actor */}
                <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '0.25rem' }}>
                  by <span style={{ fontFamily: 'monospace', fontWeight: 500, color: 'var(--accent-primary)' }}>
                    {formatActorAddress(event.actor)}
                  </span>
                </div>

                {/* Metadata */}
                {event.metadata && (
                  <>
                    {event.metadata.reason && (
                      <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginTop: '0.5rem', fontStyle: 'italic' }}>
                        "{event.metadata.reason}"
                      </div>
                    )}
                    {event.metadata.status && (
                      <div style={{ fontSize: '0.8rem', marginTop: '0.5rem' }}>
                        <span style={{
                          display: 'inline-block',
                          background: event.metadata.status === 'approved' ? 'rgba(16, 217, 160, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                          color: event.metadata.status === 'approved' ? '#10d9a0' : '#ef4444',
                          padding: '0.25rem 0.75rem',
                          borderRadius: 6,
                          fontSize: '0.75rem',
                          fontWeight: 600,
                        }}>
                          {event.metadata.status === 'approved' ? 'Γ£ô Approved' : 'Γ£ù Rejected'}
                        </span>
                      </div>
                    )}
                  </>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Icon } from './Icon';
import { SearchUsersModal } from './SearchUsersModal';

interface Contact {
  address: string;
  username: string;
  displayName: string;
  avatar: string | null;
}

interface Props {
  onClose: () => void;
  onSelectContact: (contact: Contact) => void;
  privy_id: string;
}

export function ContactPickerModal({ onClose, onSelectContact, privy_id }: Props) {
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [loading, setLoading] = useState(true);
  const [showSearch, setShowSearch] = useState(false);

  useEffect(() => {
    fetchContacts();
  }, [privy_id]);

  const fetchContacts = async () => {
    try {
      const response = await fetch(`/api/contacts?privy_id=${privy_id}`);
      if (!response.ok) throw new Error('Failed to fetch contacts');
      
      const data = await response.json();
      setContacts(data.contacts || []);
    } catch (err) {
      console.error('Failed to fetch contacts:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddContact = (newContact: Contact) => {
    setContacts(prev => [...prev, newContact]);
    setShowSearch(false);
  };

  const handleSelectContact = (contact: Contact) => {
    onSelectContact(contact);
    onClose();
  };

  if (showSearch) {
    return (
      <SearchUsersModal
        onClose={() => setShowSearch(false)}
        onAddContact={handleAddContact}
        privy_id={privy_id}
      />
    );
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box" style={{ maxWidth: '550px' }} onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="modal-header">
          <div>
            <div className="modal-title" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <Icon name="group_add" size={24} />
              Select Partner
            </div>
            <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)', marginTop: '0.25rem' }}>
              Choose who to invite to this plan
            </div>
          </div>
          <button className="modal-close" onClick={onClose}>
            <Icon name="close" size={16} />
          </button>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-muted)' }}>
            <span className="spinner" style={{ width: 20, height: 20, borderTopColor: 'var(--accent-primary)' }} />
          </div>
        ) : (
          <>
            {/* Add New Contact Button */}
            <div style={{ marginBottom: '1.5rem' }}>
              <button
                className="btn-secondary"
                onClick={() => setShowSearch(true)}
                style={{
                  width: '100%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '0.5rem',
                  padding: '0.75rem 1rem',
                }}
              >
                <Icon name="person_add" size={16} />
                Find New Contact
              </button>
            </div>

            {/* Contacts Grid (Quick Transfer style) */}
            {contacts.length > 0 ? (
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))',
                gap: '1rem',
                marginBottom: '1rem',
              }}>
                {contacts.map(contact => (
                  <button
                    key={contact.address}
                    onClick={() => handleSelectContact(contact)}
                    style={{
                      background: 'transparent',
                      border: 'none',
                      cursor: 'pointer',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      gap: '0.5rem',
                      padding: '0.75rem',
                      borderRadius: 12,
                      transition: 'background 0.2s',
                    }}
                    onMouseEnter={e => {
                      (e.currentTarget as HTMLElement).style.background = 'var(--bg-card)';
                    }}
                    onMouseLeave={e => {
                      (e.currentTarget as HTMLElement).style.background = 'transparent';
                    }}
                  >
                    <div style={{
                      width: 56,
                      height: 56,
                      borderRadius: '50%',
                      background: `hsl(${Math.random() * 360}, 70%, 60%)`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      color: 'white',
                      fontSize: '1.5rem',
                      fontWeight: 600,
                    }}>
                      {contact.avatar || contact.displayName.charAt(0).toUpperCase()}
                    </div>
                    <div style={{
                      fontSize: '0.75rem',
                      fontWeight: 600,
                      color: 'var(--text-primary)',
                      textAlign: 'center',
                      whiteSpace: 'nowrap',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      maxWidth: '100%',
                    }}>
                      {contact.displayName.length > 10
                        ? contact.displayName.slice(0, 10) + '...'
                        : contact.displayName}
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <div style={{
                textAlign: 'center',
                padding: '2rem 1rem',
                color: 'var(--text-muted)',
              }}>
                <Icon name="person" size={40} style={{ opacity: 0.2, marginBottom: '1rem' }} />
                <div style={{ marginBottom: '1rem' }}>No contacts yet</div>
                <div style={{ fontSize: '0.85rem' }}>
                  Search and add friends to invite them to plans
                </div>
              </div>
            )}

            {/* Show more info about selected contact */}
            <div style={{
              borderTop: '1px solid var(--border-subtle)',
              paddingTop: '1rem',
              marginTop: '1rem',
              fontSize: '0.8rem',
              color: 'var(--text-muted)',
              textAlign: 'center',
            }}>
              ≡ƒÆí Click a contact to invite them
            </div>
          </>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Icon } from './Icon';
import type { SavingsPlan, PlanCategory, PlanType, TokenSymbol, ChainName } from '../types';
import { CATEGORIES, TOKENS, CHAINS } from '../types';
import { ContactPickerModal } from './ContactPickerModal';

interface Props {
  onClose: () => void;
  onCreated: (plan: SavingsPlan) => void;
  privy_id?: string;
}

type Step = 'type' | 'category' | 'chain' | 'details' | 'partner' | 'warning' | 'policy' | 'success';

function genId() {
  return Math.random().toString(36).slice(2, 10).toUpperCase();
}

export function CreatePlanModal({ onClose, onCreated, privy_id }: Props) {
  const [step, setStep] = useState<Step>('type');
  const [planType, setPlanType] = useState<PlanType>('individual');
  const [category, setCategory] = useState<PlanCategory>('academics');
  const [chain, setChain] = useState<ChainName>('ethereum');
  const [name, setName] = useState('');
  const [token, setToken] = useState<TokenSymbol>('USDC');
  const [target, setTarget] = useState('');
  const [partnerAddress, setPartnerAddress] = useState('');
  const [partnerName, setPartnerName] = useState('');
  const [showContactPicker, setShowContactPicker] = useState(false);

  // New Fields
  const [lockDurationDays, setLockDurationDays] = useState<number>(30);
  const [depositToDefi, setDepositToDefi] = useState<boolean>(true);
  const [policyAgreed, setPolicyAgreed] = useState<boolean>(false);
  const [sharedOnX, setSharedOnX] = useState<boolean>(false);

  const steps: Step[] = planType === 'joint' 
    ? ['type', 'category', 'chain', 'details', 'partner', 'warning', 'policy', 'success']
    : ['type', 'category', 'chain', 'details', 'warning', 'policy', 'success'];

  const stepIndex = steps.indexOf(step);
  const catConfig = CATEGORIES.find(c => c.value === category)!;

  const handleCreateAndFinish = () => {
    if (!name.trim() || !target) return;
    if (planType === 'joint' && !partnerAddress) return;

    const inviteCode = planType === 'joint' ? `EQV-${genId()}` : undefined;

    // Calculate withdrawal date
    const wDate = new Date();
    wDate.setDate(wDate.getDate() + lockDurationDays);

    const plan: SavingsPlan = {
      id: genId(),
      name: name.trim(),
      category,
      type: planType,
      token,
      chain,
      targetAmount: parseFloat(target),
      currentAmount: 0,
      myContribution: 0,
      partnerContribution: 0,
      yieldEarned: 0,
      apy: depositToDefi ? 4.2 : 0, // Mock APY
      createdAt: new Date().toISOString(),
      lockDurationDays,
      withdrawalDate: wDate.toISOString(),
      depositToDefi,
      policyAgreed,
      sharedOnX,
      partnerAddress: planType === 'joint' ? partnerAddress : undefined,
      partnerInviteCode: inviteCode,
      isPartnerAccepted: planType === 'joint',  // Auto-accept if from contacts
    };
    onCreated(plan);

    // Reward points for creating a plan
    if (privy_id) {
      fetch(`/api/users/${privy_id}/points`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ points: 100, reason: 'Created new savings plan' }),
      }).catch(err => console.error('Failed to reward points for plan creation:', err));
    }
  };

  const handleSelectPartner = (contact: any) => {
    setPartnerAddress(contact.address);
    setPartnerName(contact.displayName);
    setShowContactPicker(false);
  };

  const handleShareOnX = async () => {
    const text = `I just started saving for "${name}" on Equilibria! The ultimate multi-chain vault with auto-yield. Let's get these goals! ≡ƒÜÇ≡ƒÆ╕ #Equilibria #Savings`;
    window.open(`https://x.com/intent/tweet?text=${encodeURIComponent(text)}`, '_blank');
    setSharedOnX(true);

    if (privy_id) {
      try {
        await fetch(`/api/users/${privy_id}/points`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ points: 50, reason: 'Shared plan on X' }),
        });
      } catch (err) {
        console.error('Failed to update points for sharing:', err);
      }
    }
  };

  const stepLabelMap: Record<Step, string> = {
    type: 'Plan Type',
    category: 'Category',
    chain: 'Blockchain',
    details: 'Details',
    partner: 'Partner',
    warning: 'Rules & Warnings',
    policy: 'Policy Agreement',
    success: 'Success',
  };

  if (showContactPicker && privy_id) {
    return (
      <ContactPickerModal
        onClose={() => setShowContactPicker(false)}
        onSelectContact={handleSelectPartner}
        privy_id={privy_id}
      />
    );
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-box" onClick={e => e.stopPropagation()} style={{ maxWidth: '520px' }}>
        {/* Header */}
        <div className="modal-header">
          <div>
            <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '0.4rem' }}>
              Step {stepIndex + 1} of {steps.length} ΓÇö {stepLabelMap[step]}
            </div>
            <div className="modal-title" style={{ fontSize: '1.3rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
              <Icon name="savings" size={24} />
              Create Savings Plan
            </div>
          </div>
          {step !== 'success' && (
            <button className="modal-close" onClick={onClose}><Icon name="close" size={18} /></button>
          )}
        </div>

        {/* Step progress bar */}
        <div className="wizard-step-bar">
          {steps.map((s, i) => (
            <div
              key={s}
              className={`wizard-step-dot ${i < stepIndex ? 'done' : i === stepIndex ? 'current' : ''}`}
            />
          ))}
        </div>

        {/* ΓöÇΓöÇ STEP 1: Type ΓöÇΓöÇ */}
        {step === 'type' && (
          <div className="form-section">
            <div className="form-label" style={{ marginBottom: '1.25rem' }}>Choose your savings mode</div>
            <div className="type-toggle">
              {([
                {
                  value: 'individual' as PlanType,
                  icon: '≡ƒºæ',
                  title: 'Individual',
                  desc: 'Private savings. Fully controlled by you.',
                },
                {
                  value: 'joint' as PlanType,
                  icon: '≡ƒæÑ',
                  title: 'Joint Vault',
                  desc: 'Invite a partner. Both manage together.',
                },
              ] as const).map(t => (
                <div
                  key={t.value}
                  className={`type-card ${planType === t.value ? 'selected' : ''}`}
                  onClick={() => setPlanType(t.value)}
                >
                  <div className="type-card-icon">{t.icon}</div>
                  <div className="type-card-title">{t.title}</div>
                  <div className="type-card-desc">{t.desc}</div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ΓöÇΓöÇ STEP 2: Category ΓöÇΓöÇ */}
        {step === 'category' && (
          <div className="form-section">
            <div className="form-label" style={{ marginBottom: '1.25rem' }}>What are you saving for?</div>
            <div className="category-grid">
              {CATEGORIES.map(cat => (
                <div
                  key={cat.value}
                  className={`category-chip ${category === cat.value ? 'selected' : ''}`}
                  style={{ '--chip-color': cat.color } as React.CSSProperties}
                  onClick={() => setCategory(cat.value)}
                >
                  <span className="category-chip-emoji">{cat.emoji}</span>
                  <span className="category-chip-label">{cat.label}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ΓöÇΓöÇ STEP 3: Chain Selection ΓöÇΓöÇ */}
        {step === 'chain' && (
          <div className="form-section">
            <div className="form-label" style={{ marginBottom: '1.25rem' }}>Select blockchain network</div>
            <div className="chain-grid">
              {CHAINS.map(c => {
                const BADGE_LABELS: Record<string, string> = {
                  ethereum: 'ETH', polygon: 'MATIC', arbitrum: 'ARB',
                  base: 'BASE', optimism: 'OP', solana: 'SOL',
                };
                const BADGE_COLORS: Record<string, string> = {
                  ethereum: '#627eea', polygon: '#8247e5', arbitrum: '#28a0f0',
                  base: '#0052ff', optimism: '#ff0420', solana: '#14f195',
                };
                return (
                  <div
                    key={c.name}
                    className={`chain-chip ${chain === c.name ? 'selected' : ''}`}
                    style={{ '--chain-color': BADGE_COLORS[c.name] } as React.CSSProperties}
                    onClick={() => setChain(c.name)}
                  >
                    <div
                      className="chain-badge"
                      style={{ background: BADGE_COLORS[c.name] }}
                    >
                      {BADGE_LABELS[c.name]}
                    </div>
                    <div className="chain-chip-label">{c.label}</div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* ΓöÇΓöÇ STEP 4: Details ΓöÇΓöÇ */}
        {step === 'details' && (
          <div style={{ maxHeight: '60vh', overflowY: 'auto', paddingRight: '0.5rem' }}>
            <div className="form-section">
              <label className="form-label">Vault Name</label>
              <input
                className="form-input"
                placeholder={`e.g. ${catConfig.emoji} My ${catConfig.label} Fund`}
                value={name}
                onChange={e => setName(e.target.value)}
                autoFocus
              />
            </div>

            <div className="form-section">
              <div className="form-label">Stablecoin</div>
              <div className="token-selector">
                {TOKENS.map(tok => (
                  <div
                    key={tok.symbol}
                    className={`token-chip ${token === tok.symbol ? 'selected' : ''}`}
                    style={{ '--tok-color': tok.color } as React.CSSProperties}
                    onClick={() => setToken(tok.symbol)}
                  >
                    <span>{tok.icon}</span>
                    <span>{tok.symbol}</span>
                  </div>
                ))}
              </div>
            </div>

            <div className="form-section">
              <label className="form-label">Target Amount</label>
              <div style={{ position: 'relative' }}>
                <input
                  className="form-input"
                  type="number"
                  placeholder="e.g. 1000"
                  min="1"
                  value={target}
                  onChange={e => setTarget(e.target.value)}
                  style={{ paddingRight: '3.5rem' }}
                />
                <span style={{ position: 'absolute', right: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)', fontWeight: 700, fontSize: '0.9rem' }}>
                  {token}
                </span>
              </div>
            </div>

            <div className="form-section">
              <label className="form-label">Lock Duration</label>
              {/* Preset chips */}
              <div className="lock-preset-grid" style={{ marginBottom: '1rem' }}>
                {[
                  { label: '1 week',   days: 7 },
                  { label: '1 month',  days: 30 },
                  { label: '3 months', days: 90 },
                  { label: '6 months', days: 180 },
                  { label: '1 year',   days: 365 },
                ].map(opt => (
                  <button
                    key={opt.days}
                    className={`lock-preset-btn ${lockDurationDays === opt.days ? 'selected' : ''}`}
                    onClick={() => setLockDurationDays(opt.days)}
                    type="button"
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
              {/* Custom number input */}
              <div className="input-with-suffix">
                <input
                  className="form-input"
                  type="number"
                  min="1"
                  max="730"
                  value={lockDurationDays}
                  onChange={e => setLockDurationDays(Math.max(1, parseInt(e.target.value) || 1))}
                  style={{ paddingRight: '4rem' }}
                />
                <span className="input-suffix">days</span>
