import { useState, useEffect } from 'react';
import { Icon } from './Icon';
import type { SavingsPlan } from '../types';
import { CATEGORIES } from '../types';
import { DepositModal } from './DepositModal';
import { WithdrawalModal } from './WithdrawalModal';
import { WithdrawalApprovalList, type WithdrawalRequest } from './WithdrawalApprovalList';
import { ActivityFeed, type ActivityEvent } from './ActivityFeed';

interface Props {
  plan: SavingsPlan;
  wallet: any;
  onBack: () => void;
  onUpdatePlan: (plan: SavingsPlan) => void;
}



export function SharedVault({ plan, wallet, onBack, onUpdatePlan }: Props) {
  const [showDeposit, setShowDeposit] = useState(false);
  const [showWithdrawal, setShowWithdrawal] = useState(false);
  const [withdrawalRequests, setWithdrawalRequests] = useState<WithdrawalRequest[]>([]);
  const [activityEvents, setActivityEvents] = useState<ActivityEvent[]>([]);
  const [copiedCode, setCopiedCode] = useState(false);
  const cat = CATEGORIES.find(c => c.value === plan.category)!;
  const progress = plan.targetAmount > 0
    ? Math.min((plan.currentAmount / plan.targetAmount) * 100, 100)
    : 0;

  const youPct = plan.currentAmount > 0
    ? Math.round((plan.myContribution / plan.currentAmount) * 100)
    : 50;
  const partnerPct = 100 - youPct;

  // Load withdrawal requests
  useEffect(() => {
    const loadWithdrawalRequests = async () => {
      try {
        const response = await fetch(`/api/withdrawals/${plan.id}`);
        if (response.ok) {
          const data = await response.json();
          setWithdrawalRequests(data.requests.map((r: any) => ({
            id: r._id,
            planId: r.planId,
            requestedBy: r.requestedBy,
            amount: r.amount,
            reason: r.reason,
            status: r.status,
            creatorApproved: r.creatorApproved,
            partnerApproved: r.partnerApproved,
            createdAt: new Date(r.createdAt),
          })));
        }
      } catch (err) {
        console.error('Failed to load withdrawal requests:', err);
      }
    };
    loadWithdrawalRequests();
  }, [plan.id]);

  // Load activity feed
  useEffect(() => {
    const loadActivityFeed = async () => {
      try {
        const response = await fetch(`/api/activity/${plan.id}`);
        if (response.ok) {
          const data = await response.json();
          setActivityEvents(data.logs.map((log: any) => ({
            id: log._id,
            planId: log.planId,
            type: log.type,
            actor: log.actor,
            amount: log.amount,
            metadata: log.metadata,
            createdAt: log.createdAt,
          })));
        }
      } catch (err) {
        console.error('Failed to load activity feed:', err);
      }
    };
    loadActivityFeed();
  }, [plan.id]);

  const handleCopy = () => {
    if (plan.partnerInviteCode) {
      navigator.clipboard.writeText(`${window.location.origin}?invite=${plan.partnerInviteCode}`);
      setCopiedCode(true);
      setTimeout(() => setCopiedCode(false), 2000);
    }
  };

  const handleSimulateAccept = () => {
    onUpdatePlan({ ...plan, isPartnerAccepted: true });
  };

  const handleRequestWithdrawal = async (amount: number, reason: string) => {
    try {
      // Get current user address from localStorage or wallet - for now use wallet metadata
      const userAddress = wallet?.address || 'user';

      const response = await fetch('/api/withdrawals', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          planId: plan.id,
          requestedBy: userAddress,
          amount,
          reason,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to request withdrawal');
      }

      const data = await response.json();
      const newRequest = {
        id: data.request._id,
        planId: data.request.planId,
        requestedBy: data.request.requestedBy,
        amount: data.request.amount,
        reason: data.request.reason,
        status: data.request.status,
        creatorApproved: data.request.creatorApproved,
        partnerApproved: data.request.partnerApproved,
        createdAt: new Date(data.request.createdAt),
      };

      setWithdrawalRequests(prev => [newRequest, ...prev]);

      // Log activity event
      await fetch('/api/activity', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          planId: plan.id,
          type: 'withdrawal_requested',
          actor: userAddress,
          amount,
          metadata: { reason },
        }),
      });
    } catch (err) {
      throw err;
    }
  };

  const handleApproveWithdrawal = async (requestId: string) => {
    try {
      const userAddress = wallet?.address || 'user';

      const response = await fetch(`/api/withdrawals/${requestId}/approve`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          approverAddress: userAddress,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to approve withdrawal');
      }

      const data = await response.json();
      const request = withdrawalRequests.find(r => r.id === requestId);

      setWithdrawalRequests(prev =>
        prev.map(r => r.id === requestId
          ? {
              ...r,
              creatorApproved: data.request.creatorApproved,
              partnerApproved: data.request.partnerApproved,
              status: data.request.status,
            }
          : r
        )
      );

      // Log approval event
      await fetch('/api/activity', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          planId: plan.id,
          type: 'withdrawal_approved',
          actor: userAddress,
          amount: request?.amount || 0,
          metadata: { status: data.request.status },
        }),
      });
    } catch (err) {
      throw err;
    }
  };

  const handleRejectWithdrawal = async (requestId: string) => {
    try {
      const userAddress = wallet?.address || 'user';

      const response = await fetch(`/api/withdrawals/${requestId}/reject`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          rejectedBy: userAddress,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to reject withdrawal');
      }

      const data = await response.json();

      setWithdrawalRequests(prev =>
        prev.map(r => r.id === requestId
          ? { ...r, status: data.request.status }
          : r
        )
      );

      // Log rejection event (already logged on backend)
    } catch (err) {
      throw err;
    }
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>
      <button className="btn-ghost" style={{ marginBottom: '1.5rem', paddingLeft: 0 }} onClick={onBack}>
        <Icon name="arrow_back" size={16} /> Back to Dashboard
      </button>

      <div className="greeting-section" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
        <div>
          <h1 className="greeting-title">{plan.name}</h1>
          <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', marginTop: '0.5rem' }}>
            <span className="badge badge-purple"><Icon name="group" size={12} /> Joint Vault</span>
            <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>Shared Household Goal</span>
          </div>
        </div>
        <div style={{ fontSize: '2.5rem' }}>{cat.emoji}</div>
      </div>

      {/* Balance Card */}
      <div className="balance-card" style={{ marginBottom: '2rem' }}>
        <div className="balance-label">Total Vault Savings</div>
        <div className="balance-amount">${plan.currentAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</div>
        <div style={{ marginTop: '1rem', fontSize: '1rem', display: 'flex', alignItems: 'center', gap: '1rem' }}>
           <span>Target: ${plan.targetAmount.toLocaleString()} {plan.token}</span>
           <div style={{ flex: 1, height: '6px', background: 'rgba(255,255,255,0.2)', borderRadius: 10, overflow: 'hidden' }}>
             <div style={{ width: `${progress}%`, height: '100%', background: 'white' }} />
           </div>
        </div>

        <div className="balance-actions">
           <button className="btn-white" onClick={() => setShowDeposit(true)} style={{ flex: 1 }}>
             <Icon name="download" size={16} /> Add Funds
           </button>
           <button
             className="btn-white"
             onClick={() => setShowWithdrawal(true)}
             style={{ flex: 1, padding: '0.8rem', background: '#fff', color: '#000', border: '1px solid #ddd' }}
           >
             <Icon name="upload" size={16} /> Request Withdrawal
           </button>
        </div>
      </div>

      {/* Vault Terms */}
      <div className="section-header">
        <h3 className="section-title"><Icon name="lock" size={18} style={{ marginRight: '0.5rem' }} /> Vault Terms</h3>
      </div>
      <div className="chart-card" style={{ marginBottom: '2rem', display: 'flex', flexWrap: 'wrap', gap: '2rem' }}>
        <div>
          <div className="card-label">Created On</div>
          <div style={{ fontSize: '1.1rem', fontWeight: 700, color: 'var(--text-primary)', marginTop: '0.25rem' }}>
            {new Date(plan.createdAt).toLocaleDateString()}
          </div>
        </div>
        <div>
          <div className="card-label">Lock Duration</div>
          <div style={{ fontSize: '1.1rem', fontWeight: 700, color: 'var(--text-primary)', marginTop: '0.25rem' }}>
            {plan.lockDurationDays || 30} Days
          </div>
        </div>
        <div>
          <div className="card-label">Unlock Date</div>
          <div style={{ fontSize: '1.1rem', fontWeight: 700, color: 'var(--accent-primary)', marginTop: '0.25rem' }}>
            {plan.withdrawalDate ? new Date(plan.withdrawalDate).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' }) : 'N/A'}
          </div>
        </div>
      </div>

      {/* Split Logic */}
      <div className="section-header">
        <h3 className="section-title">Contribution Split</h3>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '2rem' }}>
        <div className="chart-card">
          <div className="card-label">Your Contribution ({youPct}%)</div>
          <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-primary)', marginTop: '0.5rem' }}>
            ${plan.myContribution.toLocaleString()}
          </div>
          <div style={{ width: '100%', height: '4px', background: 'var(--bg-input)', borderRadius: 10, marginTop: '0.6rem', overflow: 'hidden' }}>
            <div style={{ width: `${youPct}%`, height: '100%', background: 'var(--accent-primary)' }} />
          </div>
        </div>

        <div className="chart-card">
          <div className="card-label">Partner's Contribution ({partnerPct}%)</div>
          <div style={{ fontSize: '1.5rem', fontWeight: 800, color: '#a78bfa', marginTop: '0.5rem' }}>
            ${plan.partnerContribution.toLocaleString()}
          </div>
          <div style={{ width: '100%', height: '4px', background: 'var(--bg-input)', borderRadius: 10, marginTop: '0.6rem', overflow: 'hidden' }}>
            <div style={{ width: `${partnerPct}%`, height: '100%', background: '#a78bfa' }} />
          </div>
        </div>
      </div>

      {/* Partner Connection */}
      <div className="tx-list" style={{ padding: '1.5rem', marginBottom: '2rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
          <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
            <Icon name="group" size={20} color={plan.isPartnerAccepted ? 'var(--success)' : 'var(--text-muted)'} />
            <div style={{ fontWeight: 800, fontSize: '1rem', color: 'var(--text-primary)' }}>Partner Connection</div>
          </div>
          {plan.isPartnerAccepted 
            ? <div className="badge" style={{ background: 'var(--success)', color: 'white' }}>Connected</div>
            : <div className="badge badge-orange">Pending</div>
          }
        </div>

        {!plan.isPartnerAccepted && (
          <div style={{ background: 'var(--bg-input)', padding: '1rem', borderRadius: 12 }}>
            <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '0.75rem' }}>
              Your partner hasn't joined this vault yet. Share your invite code:
            </p>
            <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
              <div style={{ flex: 1, background: 'var(--bg-sidebar)', padding: '0.6rem 1rem', borderRadius: 8, fontFamily: 'monospace', fontWeight: 700, color: 'var(--accent-primary)', border: '1px solid var(--border-subtle)' }}>
                {plan.partnerInviteCode}
              </div>
              <button className="btn-icon" onClick={handleCopy}>
                {copiedCode ? <Icon name="check" size={16} color="var(--success)" /> : <Icon name="content_copy" size={16} />}
              </button>
            </div>
            <button className="btn-ghost" style={{ marginTop: '0.5rem', fontSize: '0.8rem' }} onClick={handleSimulateAccept}>
              ≡ƒÄ¡ Demo: Simulate Partner Join
            </button>
          </div>
        )}

        {plan.isPartnerAccepted && (
          <div style={{ display: 'flex', gap: '0.75rem', color: 'var(--text-muted)', fontSize: '0.85rem', alignItems: 'center' }}>
            <Icon name="check" size={14} color="var(--success)" /> Both partners have full transparency and access.
          </div>
        )}
      </div>

      {/* Withdrawal Approvals */}
      {plan.type === 'joint' && withdrawalRequests.length > 0 && (
        <div style={{ marginBottom: '2.5rem' }}>
          <div className="section-header">
            <h3 className="section-title">Withdrawals</h3>
          </div>
          <WithdrawalApprovalList
            requests={withdrawalRequests}
            currentUserAddress={wallet?.address || ''}
            isCreator={true}
            onApprove={handleApproveWithdrawal}
            onReject={handleRejectWithdrawal}
          />
        </div>
      )}

      {/* Yield Status */}
      <div className="section-header">
        <h3 className="section-title">Vault Performance</h3>
      </div>
      <div className="chart-card" style={{ marginBottom: '2.5rem' }}>
        <div style={{ display: 'flex', gap: '2rem' }}>
          <div>
            <div className="card-label">Total Rewards</div>
            <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--success)' }}>
              +{(plan.yieldEarned || 0).toFixed(4)} <span style={{ fontSize: '0.85rem' }}>{plan.token}</span>
            </div>
          </div>
          <div>
            <div className="card-label">Current APY</div>
            <div style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--accent-primary)' }}>
              ~{plan.apy}%
            </div>
          </div>
        </div>
      </div>

      {/* Activity Feed */}
      <div className="section-header" style={{ marginTop: '2.5rem', marginBottom: '1.5rem' }}>
        <h3 className="section-title"><Icon name="timeline" size={18} style={{ marginRight: '0.5rem' }} />Activity Timeline</h3>
      </div>
      <div className="tx-list" style={{ marginBottom: '2.5rem' }}>
        <ActivityFeed events={activityEvents} isLoading={false} />
      </div>

      {showDeposit && (
        <DepositModal
          plan={plan}
          wallet={wallet}
          onClose={() => setShowDeposit(false)}
          onDeposited={(updatedPlan) => {
            onUpdatePlan(updatedPlan);
            setShowDeposit(false);
          }}
        />
      )}

      {showWithdrawal && (
        <WithdrawalModal
          plan={plan}
          myContribution={plan.myContribution}
          partnerContribution={plan.partnerContribution}
          onClose={() => setShowWithdrawal(false)}
          onSubmit={handleRequestWithdrawal}
        />
      )}
    </div>
  );
}

