import { useState } from 'react';
import { Icon } from './Icon';
import type { SavingsPlan } from '../types';

type SwapToken = 'ETH' | 'USDC' | 'USDT';

const SWAP_TOKENS: { symbol: SwapToken; name: string; color: string; balance: string }[] = [
  { symbol: 'ETH',  name: 'Ethereum',  color: '#627eea', balance: '0.425' },
  { symbol: 'USDC', name: 'USD Coin',  color: '#2775ca', balance: '850.00' },
  { symbol: 'USDT', name: 'Tether USD', color: '#26a17b', balance: '500.00' },
];

const RATES: Record<string, number> = {
  'ETH-USDC':  2409, 'USDC-ETH':  0.000415,
  'ETH-USDT':  2409, 'USDT-ETH':  0.000415,
  'USDC-USDT': 1.0,  'USDT-USDC': 1.0,
};

interface Props {
  plans: SavingsPlan[];
  wallet?: any;
}

export function SwapPage({ plans: _plans, wallet: _wallet }: Props) {
  const [fromToken, setFromToken] = useState<SwapToken>('ETH');
  const [toToken,   setToToken]   = useState<SwapToken>('USDC');
  const [fromAmt,   setFromAmt]   = useState('');
  const [slippage,  setSlippage]  = useState(0.5);
  const [swapping,  setSwapping]  = useState(false);
  const [swapped,   setSwapped]   = useState(false);

  const rateKey = `${fromToken}-${toToken}`;
  const rate = RATES[rateKey] ?? 1;
  const toAmt = fromAmt ? (parseFloat(fromAmt) * rate).toFixed(6) : '';

  const flip = () => {
    setFromToken(toToken);
    setToToken(fromToken);
    setFromAmt(toAmt);
  };

  const handleSwap = async () => {
    if (!fromAmt || parseFloat(fromAmt) <= 0) return;
    setSwapping(true);
    await new Promise(r => setTimeout(r, 1800));
    setSwapping(false);
    setSwapped(true);
    setFromAmt('');
    setTimeout(() => setSwapped(false), 3000);
  };

  const TokenSelector = ({
    value, onChange, exclude,
  }: { value: SwapToken; onChange: (t: SwapToken) => void; exclude: SwapToken }) => {
    return (
      <div style={{ position: 'relative' }}>
        <select
          value={value}
          onChange={e => onChange(e.target.value as SwapToken)}
          style={{
            background: 'var(--bg-card)',
            border: '1.5px solid var(--border-default)',
            borderRadius: '10px',
            padding: '0.5rem 2rem 0.5rem 0.85rem',
            fontSize: '0.9rem',
            fontWeight: 700,
            color: 'var(--text-primary)',
            cursor: 'pointer',
            appearance: 'none',
            minWidth: '100px',
            fontFamily: 'var(--font)',
          }}
        >
          {SWAP_TOKENS.filter(t => t.symbol !== exclude).map(t => (
            <option key={t.symbol} value={t.symbol}>
              {t.symbol}
            </option>
          ))}
        </select>
        <span style={{
          position: 'absolute', right: '0.5rem', top: '50%',
          transform: 'translateY(-50%)', pointerEvents: 'none',
          color: 'var(--text-muted)', fontSize: '0.7rem',
        }}>Γû╛</span>
      </div>
    );
  };

  return (
    <div style={{ maxWidth: '480px', margin: '0 auto' }}>
      {/* Header */}
      <div style={{ marginBottom: '1.75rem' }}>
        <h1 className="greeting-title">Swap Tokens</h1>
        <p className="greeting-sub">Exchange tokens instantly via cross-chain DEX aggregation.</p>
      </div>

      {/* Main swap card */}
      <div className="bank-card" style={{ minHeight: 'auto', cursor: 'default', marginBottom: '1rem', padding: '1.5rem' }}>

        {/* From */}
        <div style={{ background: 'var(--bg-input)', borderRadius: '12px', padding: '1rem 1.1rem', marginBottom: '0.4rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.6rem' }}>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em' }}>You Pay</span>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
              Balance: {SWAP_TOKENS.find(t => t.symbol === fromToken)?.balance ?? '0.000'} {fromToken}
            </span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <input
              type="number"
              value={fromAmt}
              onChange={e => setFromAmt(e.target.value)}
              placeholder="0.00"
              style={{
                flex: 1, background: 'transparent', border: 'none',
                fontSize: '1.75rem', fontWeight: 800, color: 'var(--text-primary)',
                outline: 'none', minWidth: 0, fontFamily: 'var(--font)',
              }}
            />
            <TokenSelector value={fromToken} onChange={setFromToken} exclude={toToken} />
          </div>
        </div>

        {/* Flip button */}
        <div style={{ display: 'flex', justifyContent: 'center', margin: '0.2rem 0' }}>
          <button
            onClick={flip}
            style={{
              width: 36, height: 36, borderRadius: '50%',
              background: 'var(--bg-card)', border: '1.5px solid var(--border-default)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              cursor: 'pointer', transition: 'transform 0.25s ease, border-color 0.2s',
              color: 'var(--accent-primary)',
            }}
            onMouseEnter={e => { (e.currentTarget as HTMLButtonElement).style.transform = 'rotate(180deg)'; }}
            onMouseLeave={e => { (e.currentTarget as HTMLButtonElement).style.transform = 'rotate(0)'; }}
            title="Flip tokens"
          >
            <Icon name="swap_vert" size={18} />
          </button>
        </div>

        {/* To */}
        <div style={{ background: 'var(--bg-input)', borderRadius: '12px', padding: '1rem 1.1rem', marginTop: '0.2rem', marginBottom: '1.25rem' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.6rem' }}>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em' }}>You Receive</span>
            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
              Balance: {SWAP_TOKENS.find(t => t.symbol === toToken)?.balance ?? '0.000'} {toToken}
            </span>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
            <div style={{
              flex: 1, fontSize: '1.75rem', fontWeight: 800,
              color: toAmt ? 'var(--success)' : 'var(--text-muted)',
              fontFamily: 'var(--font)',
            }}>
              {toAmt || '0.00'}
            </div>
            <TokenSelector value={toToken} onChange={setToToken} exclude={fromToken} />
          </div>
        </div>

        {/* Rate info */}
        {fromAmt && parseFloat(fromAmt) > 0 && (
          <div style={{
            background: 'var(--bg-input)', borderRadius: '10px',
            padding: '0.85rem 1rem', marginBottom: '1.1rem',
            display: 'flex', flexDirection: 'column', gap: '0.5rem',
          }}>
            {[
              { label: 'Rate',         value: `1 ${fromToken} = ${rate < 0.001 ? rate.toExponential(3) : rate.toLocaleString()} ${toToken}` },
              { label: 'Slippage',     value: `${slippage}%` },
              { label: 'Network Fee',  value: '~$0.50' },
            ].map(row => (
              <div key={row.label} style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontSize: '0.78rem', color: 'var(--text-muted)', fontWeight: 600 }}>{row.label}</span>
                <span style={{ fontSize: '0.78rem', fontWeight: 700, color: 'var(--text-primary)' }}>{row.value}</span>
              </div>
            ))}
          </div>
        )}

        {/* Slippage */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1.1rem' }}>
          <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 600 }}>Slippage:</span>
          {[0.1, 0.5, 1.0].map(s => (
            <button key={s} onClick={() => setSlippage(s)} style={{
              padding: '0.28rem 0.65rem', borderRadius: '6px', border: 'none',
              cursor: 'pointer', fontSize: '0.75rem', fontWeight: 700, fontFamily: 'var(--font)',
              background: slippage === s ? 'var(--accent-primary)' : 'var(--bg-input)',
              color: slippage === s ? 'white' : 'var(--text-muted)',
              transition: 'all 0.15s',
            }}>
              {s}%
            </button>
          ))}
        </div>

        <button
          className="btn-primary"
          style={{ width: '100%', fontSize: '0.95rem', padding: '0.85rem' }}
          onClick={handleSwap}
          disabled={!fromAmt || parseFloat(fromAmt) <= 0 || swapping}
        >
          {swapping ? (
            <><span className="spinner" /> Swapping...</>
          ) : swapped ? (
            <><Icon name="check_circle" size={18} /> Swap Successful!</>
          ) : (
            <><Icon name="swap_horiz" size={18} /> Swap {fromToken} ΓåÆ {toToken}</>
          )}
        </button>
      </div>

      {/* Info note */}
      <div style={{
        display: 'flex', alignItems: 'flex-start', gap: '0.65rem',
        background: 'var(--accent-dim)', border: '1px solid var(--border-active)',
        borderRadius: '12px', padding: '0.85rem 1rem',
      }}>
        <Icon name="info" size={16} color="var(--accent-primary)" />
        <p style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', lineHeight: 1.6, margin: 0 }}>
          Swaps are routed through multi-chain DEX aggregators for best-in-class rates across Base, Arbitrum, BNB, and Solana.
        </p>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';

type Step = {
  target: string;
  content: string;
  placement?: string;
  disableBeacon?: boolean;
  placementBeacon?: string;
};

export function TourGuide() {
  const [run, setRun] = useState(false);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [Joyride, setJoyride] = useState<any>(null);

  useEffect(() => {
    import('react-joyride').then((mod) => {
      setJoyride(() => mod.default || (mod as any).Joyride || mod);
    }).catch(console.error);
  }, []);

  useEffect(() => {
    if (!Joyride) return;
    const hasSeenTour = localStorage.getItem('has_seen_tour');
    if (!hasSeenTour) {
      const timer = setTimeout(() => setRun(true), 1200);
      return () => clearTimeout(timer);
    }
  }, [Joyride]);

  // Listen for manual tour trigger
  useEffect(() => {
    const handleStartTour = () => {
      setRun(true);
    };
    window.addEventListener('startTour', handleStartTour);
    return () => window.removeEventListener('startTour', handleStartTour);
  }, []);

  const handleCallback = (data: { status: string }) => {
    if (data.status === 'finished' || data.status === 'skipped') {
      setRun(false);
      localStorage.setItem('has_seen_tour', 'true');
    }
  };

  const steps: Step[] = [
    {
      target: 'body',
      content: '≡ƒæï Welcome to Equilibria Vault! Let me give you a quick tour of your smart savings app.',
      placement: 'center',
      disableBeacon: true,
    },
    {
      // Target the balance card inside dashboard - more specific so tooltip renders inside view
      target: '.balance-card',
      content: '≡ƒÆ╝ This is your Total Portfolio Balance - see your cumulative savings, toggle holdings, and perform quick actions like Send, Request, Split, or Top Up.',
      placement: 'bottom',
      disableBeacon: true,
    },
    {
      target: '#user-wallet-dropdown',
      content: 'ΓÜÖ∩╕Å Click your wallet chip here to access Profile Settings, change your display name, or logout securely.',
      placement: 'bottom',
      disableBeacon: true,
    },
    {
      target: '#plans-create-btn',
      content: '≡ƒÜÇ Ready to save? Click "Create Plan" to start an individual private vault or a joint savings plan with a partner!',
      placement: 'left',
      disableBeacon: true,
    },
  ];

  if (!Joyride) return null;

  return (
    <Joyride
      callback={handleCallback}
      continuous
      hideCloseButton={false}
      run={run}
      scrollToFirstStep
      scrollOffset={80}
      disableScrolling={false}
      showProgress
      showSkipButton
      steps={steps}
      floaterProps={{
        disableAnimation: false,
        hideArrow: false,
        offset: 14,
        options: {
          preventOverflow: {
            boundariesElement: 'window',
          },
        },
      }}
      styles={{
        options: {
          zIndex: 10000,
          primaryColor: '#ff8c00',
          textColor: '#1a1d23',
          backgroundColor: '#ffffff',
          arrowColor: '#ffffff',
          width: 340,
        },
        tooltip: {
          borderRadius: '16px',
          boxShadow: '0 8px 32px rgba(0,0,0,0.15)',
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          fontSize: '0.9rem',
          lineHeight: 1.6,
          padding: '1.25rem 1.5rem',
        },
        tooltipContent: {
          padding: '0.5rem 0 0.25rem',
        },
        buttonNext: {
          borderRadius: '10px',
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          fontWeight: 700,
          padding: '0.65rem 1.5rem',
          fontSize: '0.85rem',
          backgroundColor: '#000000',
          color: '#ffffff',
          border: '1px solid #333333',
        },
        buttonSkip: {
          color: '#666',
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          fontSize: '0.82rem',
          backgroundColor: 'transparent',
          border: '1px solid #e0e0e0',
          padding: '0.5rem 1.2rem',
          borderRadius: '8px',
        },
        buttonBack: {
          color: '#000000',
          fontFamily: "'Plus Jakarta Sans', sans-serif",
          fontSize: '0.82rem',
          backgroundColor: '#f5f5f5',
          border: '1px solid #ddd',
          padding: '0.5rem 1rem',
          borderRadius: '8px',
        },
        buttonClose: {
          color: '#aaa',
          top: 12,
          right: 12,
          width: 20,
          height: 20,
        },
      }}
    />
  );
}

import { useState, useEffect } from 'react';
import { Icon } from './Icon';

interface UserData {
  privy_id: string;
  address: string;
  username: string;
  displayName: string;
  avatar: string | null;
  bio: string;
  createdAt: string;
}

interface Props {
  username: string;
  currentUserPrivy_id?: string;
  onAddContact?: (user: UserData) => void;
  onClose?: () => void;
}

export function UserProfile({ username, currentUserPrivy_id, onAddContact, onClose }: Props) {
  const [user, setUser] = useState<UserData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [isContact, setIsContact] = useState(false);
  const [isAdding, setIsAdding] = useState(false);

  useEffect(() => {
    fetchUserProfile();
  }, [username]);

  const fetchUserProfile = async () => {
    try {
      setLoading(true);
      setError('');

      // Search for user by username
      const response = await fetch(`/api/users/search?q=@${username}`);
      if (!response.ok) throw new Error('User not found');

      const data = await response.json();
      const foundUser = data.results?.[0];

      if (!foundUser) throw new Error('User not found');

      // Fetch full profile
      const profileResponse = await fetch(`/api/users/${foundUser.address}`);
      if (!profileResponse.ok) throw new Error('Failed to load profile');

      const profileData = await profileResponse.json();
      setUser(profileData);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleAddContact = async () => {
    if (!user || !currentUserPrivy_id) return;

    setIsAdding(true);
    try {
      const response = await fetch('/api/contacts', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          privy_id: currentUserPrivy_id,
          contactAddress: user.address,
        }),
      });

      if (!response.ok) throw new Error('Failed to add contact');

      setIsContact(true);
      if (onAddContact) onAddContact(user);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to add contact');
    } finally {
      setIsAdding(false);
    }
  };

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '3rem 1rem',
        minHeight: '400px',
      }}>
        <span className="spinner" style={{ width: 30, height: 30, borderTopColor: 'var(--accent-primary)' }} />
      </div>
    );
  }

  if (error || !user) {
    return (
      <div style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: '3rem 1rem',
        minHeight: '400px',
        color: 'var(--text-muted)',
        textAlign: 'center',
      }}>
        <Icon name="person_off" size={48} style={{ opacity: 0.3, marginBottom: '1rem' }} />
        <div style={{ fontSize: '1.1rem', fontWeight: 600, marginBottom: '0.5rem' }}>User not found</div>
        <div style={{ fontSize: '0.9rem' }}>{error || 'This user does not exist'}</div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: '600px', margin: '0 auto', padding: '2rem 1rem' }}>
      {/* Close button if modal */}
      {onClose && (
        <button
          className="btn-ghost"
          onClick={onClose}
          style={{ marginBottom: '1rem', paddingLeft: 0 }}
        >
          <Icon name="arrow_back" size={16} /> Back
        </button>
      )}

      {/* Profile Card */}
      <div style={{
        background: 'var(--bg-card)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 16,
        padding: '2rem',
        textAlign: 'center',
      }}>
        {/* Avatar */}
        <div style={{
          width: 100,
          height: 100,
          borderRadius: '50%',
          background: `hsl(${Math.random() * 360}, 70%, 60%)`,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          fontSize: '3rem',
          fontWeight: 700,
          margin: '0 auto 1.5rem',
        }}>
          {user.avatar || user.displayName.charAt(0).toUpperCase()}
        </div>

        {/* Name */}
        <h1 style={{
          fontSize: '1.5rem',
          fontWeight: 800,
          color: 'var(--text-primary)',
          margin: 0,
          marginBottom: '0.5rem',
        }}>
          {user.displayName}
        </h1>

        {/* Username */}
        <div style={{
          fontSize: '1rem',
          color: 'var(--accent-primary)',
          fontWeight: 600,
          marginBottom: '1rem',
        }}>
          @{user.username}
        </div>

        {/* Bio */}
        {user.bio && (
          <p style={{
            fontSize: '0.95rem',
            color: 'var(--text-secondary)',
            marginBottom: '1.5rem',
            lineHeight: 1.6,
          }}>
            {user.bio}
          </p>
        )}

        {/* Address */}
        <div style={{
          background: 'var(--bg-input)',
          borderRadius: 8,
          padding: '0.75rem 1rem',
          marginBottom: '1.5rem',
          fontFamily: 'monospace',
          fontSize: '0.85rem',
          color: 'var(--text-muted)',
          wordBreak: 'break-all',
        }}>
          {user.address}
        </div>

        {/* Add Contact Button */}
        {currentUserPrivy_id && (
          <button
            className={`btn-${isContact ? 'ghost' : 'primary'}`}
            onClick={handleAddContact}
            disabled={isContact || isAdding}
            style={{ width: '100%' }}
          >
            {isContact ? (
              <>
                <Icon name="check" size={16} /> Added to Contacts
              </>
            ) : isAdding ? (
              <>
                <span className="spinner" style={{ width: 14, height: 14 }} /> Adding...
              </>
            ) : (
              <>
                <Icon name="person_add" size={16} /> Add Contact
              </>
            )}
          </button>
        )}

        {/* QR Code Section */}
        <div style={{
          marginTop: '2rem',
          paddingTop: '2rem',
          borderTop: '1px solid var(--border-subtle)',
        }}>
          <div style={{
            fontSize: '0.8rem',
            color: 'var(--text-muted)',
            marginBottom: '1rem',
            textTransform: 'uppercase',
            fontWeight: 600,
          }}>
            Share Profile
          </div>
          <div style={{
            background: 'white',
            borderRadius: 8,
            padding: '1rem',
            display: 'inline-block',
            marginBottom: '1rem',
          }}>
            {/* Placeholder QR - in production, use qrcode library */}
            <div style={{
              width: 200,
              height: 200,
              background: 'var(--bg-input)',
              borderRadius: 8,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'var(--text-muted)',
              fontSize: '0.8rem',
              textAlign: 'center',
              padding: '1rem',
            }}>
              QR Code<br/>
              {`${window.location.origin}/user/${user.username}`}
            </div>
          </div>

          {/* Share Link */}
          <div style={{
            display: 'flex',
            gap: '0.5rem',
            justifyContent: 'center',
          }}>
            <button
              className="btn-secondary"
              onClick={() => {
                const url = `${window.location.origin}/user/${user.username}`;
                navigator.clipboard.writeText(url);
              }}
              style={{ fontSize: '0.85rem' }}
            >
              <Icon name="link" size={14} /> Copy Link
            </button>
          </div>
        </div>

        {/* Member Since */}
        <div style={{
          marginTop: '2rem',
          paddingTop: '2rem',
          borderTop: '1px solid var(--border-subtle)',
          fontSize: '0.85rem',
          color: 'var(--text-muted)',
        }}>
          Member since {new Date(user.createdAt).toLocaleDateString()}
        </div>
      </div>
    </div>
  );
}

