 * In production, this would build and broadcast an on-chain transaction.
 */
export async function depositToPool(
  _wallet: any,
  token: SupportedToken,
  amountStr: string,
  _chain: SupportedChain
): Promise<{ txHash: string; apy: number }> {
  // Simulate network delay
  await new Promise(r => setTimeout(r, 1800));

  // Mock transaction hash
  const txHash = '0x' + Math.random().toString(16).slice(2).padStart(64, '0');

  const APY_RATES: Record<SupportedToken, number> = {
    ETH:  2.8,
    USDC: 4.2,
    USDT: 4.0,
    SOL:  5.1,
  };

  console.log(`Γ£à Deposited ${amountStr} ${token} - Mock TX: ${txHash}`);

  return { txHash, apy: APY_RATES[token] };
}

/**
 * Simulate withdrawing funds from a DeFi pool.
 * Returns net amount after 5% early withdrawal penalty (if applicable).
 */
export async function withdrawFromPool(
  _wallet: any,
  _token: SupportedToken,
  amountStr: string,
  _chain: SupportedChain,
  isEarlyWithdrawal: boolean
): Promise<{ txHash: string; netAmount: number; penaltyAmount: number }> {
  await new Promise(r => setTimeout(r, 1800));

  const amount = parseFloat(amountStr);
  const penaltyRate = isEarlyWithdrawal ? 0.05 : 0;
  const penaltyAmount = amount * penaltyRate;
  const netAmount = amount - penaltyAmount;
  const txHash = '0x' + Math.random().toString(16).slice(2).padStart(64, '0');

  return { txHash, netAmount, penaltyAmount };
}

